// Flujo de prueba E2E

// 1. Crear productos en Product (puerto 8082)
POST http://localhost:8082/product
{
  "name": "Cuenta de Ahorros",
  "price": 0.0
}
// Respuesta: {"id": 1, "name": "Cuenta de Ahorros", "price": 0.0}

POST http://localhost:8082/product
{
  "name": "Tarjeta de Crédito",
  "price": 50.0
}
// Respuesta: {"id": 2, "name": "Tarjeta de Crédito", "price": 50.0}

// 2. Crear customer con productos válidos (puerto 8081)
POST http://localhost:8081/customer
{
  "name": "María González",
  "phoneNumber": "555-5678",
  "productIds": [1, 2]
}
// Respuesta: {"id": 1, ...}

// 3. Consultar customer con productos completos
GET http://localhost:8081/customer/1
// Respuesta:
{
  "id": 1,
  "name": "María González",
  "phoneNumber": "555-5678",
  "products": [
    {"id": 1, "name": "Cuenta de Ahorros", "price": 0.0},
    {"id": 2, "name": "Tarjeta de Crédito", "price": 50.0}
  ]
}

// 4. Probar validación con ID inválido
POST http://localhost:8081/customer
{
  "name": "Test",
  "phoneNumber": "555-0000",
  "productIds": [999] // Producto no existe
}
// Respuesta: Error 500 con mensaje "Producto no encontrado: 999"
